from typing import List

class Solution:
    def maxOperations(self, nums: List[int]) -> int:
        if len(nums) < 2:
            return 0

        # The score is fixed as the sum of the first two elements
        target_score = nums[0] + nums[1]
        operations = 1
        i = 2

        while i + 1 < len(nums):
            if nums[i] + nums[i + 1] == target_score:
                operations += 1
                i += 2
            else:
                break

        return operations
